"""Shared helpers for parsing the Terraform under `infra/` into a resource graph.

The pytest suite imports from here so the parsing logic stays out of conftest.py
and is reusable from the candidate's own debugging scripts.
"""
from __future__ import annotations

import pathlib
from typing import Any

import hcl2

INFRA_DIR = pathlib.Path(__file__).resolve().parent / 'infra'


def _strip(value: Any) -> Any:
    """python-hcl2 returns identifier and string tokens with their literal quotes.

    Strip wrapping double-quotes so callers can compare against plain strings.
    Recurses into dicts and lists.
    """
    if isinstance(value, str):
        if len(value) >= 2 and value[0] == '"' and value[-1] == '"':
            return value[1:-1]
        return value
    if isinstance(value, list):
        return [_strip(v) for v in value]
    if isinstance(value, dict):
        return {_strip(k): _strip(v) for k, v in value.items()}
    return value


def parse_infra(infra_dir: pathlib.Path | None = None) -> dict[str, dict[str, Any]]:
    """Parse every .tf file in infra/ and return a flat {resource_type: {name: body}} dict."""
    root = infra_dir or INFRA_DIR
    parsed: dict[str, dict[str, Any]] = {}
    for tf in sorted(root.glob('*.tf')):
        with tf.open('r', encoding='utf-8') as fp:
            doc = hcl2.load(fp)
        for resource_block in doc.get('resource', []):
            for resource_type, by_name in resource_block.items():
                rt = _strip(resource_type)
                stripped_by_name = {_strip(name): _strip(body) for name, body in by_name.items()}
                parsed.setdefault(rt, {}).update(stripped_by_name)
    return parsed


def policy_attachments_for_role(parsed: dict[str, Any], role_name: str) -> list[str]:
    arns: list[str] = []
    for _, attach in parsed.get('aws_iam_role_policy_attachment', {}).items():
        target_role = attach.get('role')
        if isinstance(target_role, list):
            target_role = target_role[0] if target_role else ''
        if isinstance(target_role, str) and role_name in target_role:
            policy_arn = attach.get('policy_arn')
            if isinstance(policy_arn, list):
                policy_arn = policy_arn[0] if policy_arn else ''
            if isinstance(policy_arn, str):
                arns.append(policy_arn)
    return arns


if __name__ == '__main__':
    import json as _json
    print(_json.dumps({k: list(v.keys()) for k, v in parse_infra().items()}, indent=2))

