from infra_assertions import policy_attachments_for_role


def test_node_role_has_worker_node_policy(terraform):
    arns = policy_attachments_for_role(terraform, 'payments_eks_node_role')
    assert any('AmazonEKSWorkerNodePolicy' in a for a in arns), (
        'Worker IAM role must attach AmazonEKSWorkerNodePolicy or kubelet cannot register the node.'
    )


def test_node_role_has_ecr_readonly(terraform):
    arns = policy_attachments_for_role(terraform, 'payments_eks_node_role')
    assert any('AmazonEC2ContainerRegistryReadOnly' in a for a in arns), (
        'Worker IAM role must attach AmazonEC2ContainerRegistryReadOnly so kubelet can pull images from ECR.'
    )


def test_node_role_keeps_cni_policy(terraform):
    arns = policy_attachments_for_role(terraform, 'payments_eks_node_role')
    assert any('AmazonEKS_CNI_Policy' in a for a in arns), (
        'Worker IAM role must keep AmazonEKS_CNI_Policy for the aws-vpc-cni controller.'
    )

