def test_node_sg_allows_443_egress_to_control_plane(terraform):
    sg = terraform.get('aws_security_group', {}).get('payments_node_sg')
    assert sg is not None, 'payments_node_sg must exist'
    egress = sg.get('egress')
    if isinstance(egress, dict):
        egress = [egress]
    egress = egress or []
    blocks_443 = []
    for rule in egress:
        from_port = rule.get('from_port')
        to_port = rule.get('to_port')
        if isinstance(from_port, list):
            from_port = from_port[0]
        if isinstance(to_port, list):
            to_port = to_port[0]
        if from_port in (443, 0) and to_port in (443, 0, 65535):
            cidrs = rule.get('cidr_blocks') or []
            if isinstance(cidrs, list) and cidrs and cidrs != [[]]:
                blocks_443.append(rule)
    assert blocks_443, (
        'Worker SG must allow TCP 443 egress to reach the EKS control plane / ECR / STS endpoints.'
    )
